int linear_search(int arr[], int n, int target) {
 int i;
 for (i = 0; i < n; i++) {
 if (arr[i] == target) {
 return i;
 }
 }
 return -1;
}

void bubble_sort(int arr[], int n) {
 int i, j, temp;
 for (i = 0; i < n - 1; i++) {
 for (j = 0; j < n - i - 1; j++) {
 if (arr[j] > arr[j + 1]) {
 temp = arr[j];
 arr[j] = arr[j + 1];
 arr[j + 1] = temp;
 }
 }
 }
}
